script:
// Client Script for Doctype: Project
// Description: Milestone Calculations + Quotation Fetch

frappe.ui.form.on('Project', {
    refresh: function(frm) {
        render_summary_table(frm);
    },
    custom_quotation: function(frm) {
        if (!frm.doc.custom_quotation) return;
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Quotation',
                name: frm.doc.custom_quotation
            },
            callback: function(r) {
                if (!r.message) return;
                let quotation = r.message;
                frm.set_value('customer', quotation.party_name);
                frm.set_value('custom_total_contract_value', quotation.grand_total);
                frm.refresh_field('custom_total_contract_value');
                frm.refresh_field('customer');
            }
        });
    },
    validate: function(frm) {
        calculate_totals(frm);
    },
    after_save: function(frm) {
        frm.reload_doc();
    }
});

frappe.ui.form.on('Project Milestone', {
    item: function(frm, cdt, cdn) {
        show_quotation_items_dialog(frm, cdt, cdn);
    },
    percentage: function(frm, cdt, cdn) {
        calculate_totals(frm);
        render_summary_table(frm);
    },
    amount: function(frm, cdt, cdn) {
        calculate_totals(frm);
        render_summary_table(frm);
    },
    custom_project_milestones_remove: function(frm) {
        calculate_totals(frm);
        render_summary_table(frm);
    }
});

function render_summary_table(frm) {
    if (!frm.fields_dict['custom_milestone_summary']) return;

    let milestones = frm.doc.custom_project_milestones || [];
    let contract_value = flt(frm.doc.custom_total_contract_value);

    if (frm.doc.custom_quotation) {
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Quotation',
                name: frm.doc.custom_quotation
            },
            callback: function(r) {
                let items = r.message ? r.message.items : [];
                let q_grand_total = r.message ? flt(r.message.grand_total, 2) : 0;
                build_and_render(items, q_grand_total);
            }
        });
    } else {
        build_and_render([], 0);
    }

    function build_and_render(quotation_items, quotation_grand_total) {
        let all_rows = [];
        let grand_total_milestone_amount = 0;

        milestones.forEach(milestone => {
            if (!milestone.milestone_items_json) return;
            try {
                let items = JSON.parse(milestone.milestone_items_json);
                items.forEach((item, item_idx) => {
                    if (!item.item_code) return;
                    let orig = quotation_items[item_idx] || quotation_items.find(q => q.item_code === item.item_code);
                    let orig_amount = orig ? flt(orig.amount, 2) : null;
                    let curr_amount = flt(item.amount, 2);
                    let diff = orig_amount !== null ? flt(curr_amount - orig_amount, 2) : null;
                    let diff_html = '';
                    let adj_html = '';
                    if (diff === null) {
                        diff_html = '<span style="color:orange;">⚠️ Not in Quotation</span>';
                        adj_html = '<span style="color:#aaa;">—</span>';
                    } else if (diff === 0) {
                        diff_html = '<span style="color:green;">✅ No Change</span>';
                        adj_html = '<span style="color:#aaa;">—</span>';
                    } else if (diff > 0) {
                        diff_html = `<span style="color:orange;">⬆️ +INR ${diff}</span>`;
                        adj_html = `<span style="color:orange; font-weight:bold;">+INR ${diff}</span>`;
                    } else {
                        diff_html = `<span style="color:red;">⬇️ -INR ${Math.abs(diff)}</span>`;
                        adj_html = `<span style="color:red; font-weight:bold;">-INR ${Math.abs(diff)}</span>`;
                    }
                    all_rows.push({
                        milestone_name: milestone.milestone_name,
                        item_code: item.item_code,
                        item_name: item.item_name,
                        qty: item.qty,
                        amount: curr_amount,
                        orig_amount: orig_amount,
                        diff_html: diff_html,
                        adj_html: adj_html,
                        milestone_percentage: item.milestone_percentage,
                        milestone_amount: item.milestone_amount
                    });
                    grand_total_milestone_amount += flt(item.milestone_amount);
                });
            } catch(e) {}
        });

        if (all_rows.length === 0) {
            frm.fields_dict['custom_milestone_summary'].$wrapper.html('');
            return;
        }

        grand_total_milestone_amount = flt(grand_total_milestone_amount, 2);
        let grand_total_adj = flt(all_rows.reduce((sum, r) => {
            if (r.orig_amount !== null) {
                return sum + flt(r.amount - r.orig_amount, 2);
            }
            return sum;
        }, 0), 2);
        let adj_total_html = grand_total_adj === 0
            ? '<span style="color:#aaa;">—</span>'
            : grand_total_adj > 0
                ? `<span style="color:orange; font-weight:bold;">+INR ${grand_total_adj}</span>`
                : `<span style="color:red; font-weight:bold;">-INR ${Math.abs(grand_total_adj)}</span>`;
        let new_contract_value = flt(quotation_grand_total + grand_total_adj, 2);
        if (new_contract_value !== contract_value && new_contract_value > 0) {
            frm.set_value('custom_total_contract_value', new_contract_value);
            contract_value = new_contract_value;
        }
        let coverage_pct = contract_value > 0 ? flt((grand_total_milestone_amount / contract_value) * 100, 2) : 0;
        frm.set_value('custom_total_completed__', coverage_pct);
        let remaining = flt(contract_value - grand_total_milestone_amount, 2);
        let status_color = coverage_pct >= 100 ? '#28a745' : '#dc3545';
        let status_msg = coverage_pct >= 100
            ? '✅ All milestones cover 100% of Total Contract Value'
            : `⚠️ Milestones cover ${coverage_pct}% of Total Contract Value. Remaining: INR ${remaining}`;

        // Contract value breakdown
        let contract_diff = flt(contract_value - quotation_grand_total, 2);
        let contract_diff_html = '';
        if (quotation_grand_total === 0) {
            contract_diff_html = '<span style="color:#888;">No Quotation linked</span>';
        } else if (contract_diff === 0) {
            contract_diff_html = '<span style="color:green;">✅ Matches Quotation Grand Total</span>';
        } else if (contract_diff > 0) {
            contract_diff_html = `<span style="color:orange;">⬆️ Manually increased by INR ${contract_diff} over Quotation Grand Total</span>`;
        } else {
            contract_diff_html = `<span style="color:red;">⬇️ Manually reduced by INR ${Math.abs(contract_diff)} from Quotation Grand Total</span>`;
        }

        let rows_html = all_rows.map(row => `
            <tr>
                <td style="padding:7px; border:1px solid #d1d8dd;">${row.milestone_name || ''}</td>
                <td style="padding:7px; border:1px solid #d1d8dd;">${row.item_code}</td>
                <td style="padding:7px; border:1px solid #d1d8dd;">${row.item_name}</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">${row.qty}</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">
                    ${row.orig_amount !== null ? 'INR ' + row.orig_amount : '<span style="color:#aaa;">—</span>'}
                </td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">INR ${row.amount}</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">${row.adj_html}</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:center;">${row.diff_html}</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">${flt(row.milestone_percentage, 2)}%</td>
                <td style="padding:7px; border:1px solid #d1d8dd; text-align:right;">INR ${flt(row.milestone_amount, 2)}</td>
            </tr>
        `).join('');

        let html = `
            <div style="margin-top:10px;">
                <h6 style="font-weight:bold; margin-bottom:8px;">📋 Milestone Items Summary</h6>
                <div style="overflow-x:auto;">
                <table style="width:100%; border-collapse:collapse; font-size:13px;">
                    <thead>
                        <tr style="background:#f4f5f6; font-weight:bold;">
                            <th style="padding:8px; border:1px solid #d1d8dd;">Milestone</th>
                            <th style="padding:8px; border:1px solid #d1d8dd;">Item Code</th>
                            <th style="padding:8px; border:1px solid #d1d8dd;">Item Name</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Qty</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Quotation Amount</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Current Amount</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Adjusted Amt</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:center;">Difference</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Milestone %</th>
                            <th style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Milestone Amount</th>
                        </tr>
                    </thead>
                    <tbody>${rows_html}</tbody>
                    <tfoot>
                        <tr style="background:#e8f4fd; font-weight:bold;">
                            <td colspan="5" style="padding:8px; border:1px solid #d1d8dd; text-align:right;">
                                Total:
                            </td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;">—</td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;">
                                ${adj_total_html}
                            </td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:center;">—</td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;">—</td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right; color:#2490ef;">
                                INR ${grand_total_milestone_amount}
                            </td>
                        </tr>
                        <tr style="background:#f0f4ff;">
                            <td colspan="9" style="padding:8px; border:1px solid #d1d8dd; text-align:right; color:#555;">
                                Quotation Grand Total
                                <span style="font-weight:normal; font-size:11px; color:#888;">
                                    (${frm.doc.custom_quotation || '—'})
                                </span>:
                            </td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right; color:#555;">
                                ${quotation_grand_total > 0 ? 'INR ' + quotation_grand_total : '<span style="color:#aaa;">—</span>'}
                            </td>
                        </tr>
                        <tr style="background:#f0f4ff;">
                            <td colspan="9" style="padding:8px; border:1px solid #d1d8dd; text-align:right; color:#555;">
                                Manual Adjustment:
                            </td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;">
                                ${adj_total_html}
                            </td>
                        </tr>
                        <tr style="background:#e8f4fd; font-weight:bold; border-top:2px solid #2490ef;">
                            <td colspan="9" style="padding:8px; border:1px solid #d1d8dd; text-align:right;">
                                = Total Contract Value:
                            </td>
                            <td style="padding:8px; border:1px solid #d1d8dd; text-align:right; color:#2490ef;">
                                INR ${flt(contract_value, 2)}
                            </td>
                        </tr>
                        <tr style="background:#fff8e1;">
                            <td colspan="10" style="padding:8px; border:1px solid #d1d8dd; text-align:center; font-size:12px;">
                                ${contract_diff_html}
                            </td>
                        </tr>
                        <tr style="background:#fff8e1;">
                            <td colspan="10" style="padding:8px; border:1px solid #d1d8dd; text-align:center; color:${status_color}; font-weight:bold;">
                                ${status_msg}
                            </td>
                        </tr>
                    </tfoot>
                </table>
                </div>
            </div>
        `;

        frm.fields_dict['custom_milestone_summary'].$wrapper.html(html);
    }
}


function render_comparison_table(quotation_items, current_items) {
    let rows = quotation_items.map((orig, idx) => {
        let current = current_items[idx] || current_items.find(i => i.item_code === orig.item_code);
        let current_amount = current ? flt(current.amount, 2) : 0;
        let orig_amount = flt(orig.amount, 2);
        let diff = flt(current_amount - orig_amount, 2);
        let status = diff === 0
            ? '<span style="color:green;">✅ No Change</span>'
            : diff > 0
                ? `<span style="color:orange;">⬆️ Increased by INR ${diff}</span>`
                : `<span style="color:red;">⬇️ Reduced by INR ${Math.abs(diff)}</span>`;

        return `
            <tr>
                <td style="padding:6px; border:1px solid #d1d8dd;">${orig.item_code}</td>
                <td style="padding:6px; border:1px solid #d1d8dd;">${orig.item_name}</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:right;">INR ${orig_amount}</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:right;">INR ${current_amount}</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:center;">${status}</td>
            </tr>
        `;
    });

    let extra_rows = current_items
        .filter(i => i.item_code && !quotation_items.find(q => q.item_code === i.item_code))
        .map(item => `
            <tr style="background:#fff3cd;">
                <td style="padding:6px; border:1px solid #d1d8dd;">${item.item_code}</td>
                <td style="padding:6px; border:1px solid #d1d8dd;">${item.item_name}</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:right;">-</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:right;">INR ${flt(item.amount, 2)}</td>
                <td style="padding:6px; border:1px solid #d1d8dd; text-align:center;">
                    <span style="color:orange;">⚠️ Not in Quotation</span>
                </td>
            </tr>
        `);

    return `
        <div style="margin-top:15px;">
            <h6 style="font-weight:bold; margin-bottom:8px; color:#495057;">
                📊 Amount Comparison vs Quotation
            </h6>
            <table style="width:100%; border-collapse:collapse; font-size:12px;">
                <thead>
                    <tr style="background:#f4f5f6; font-weight:bold;">
                        <th style="padding:7px; border:1px solid #d1d8dd;">Item Code</th>
                        <th style="padding:7px; border:1px solid #d1d8dd;">Item Name</th>
                        <th style="padding:7px; border:1px solid #d1d8dd; text-align:right;">Quotation Amount</th>
                        <th style="padding:7px; border:1px solid #d1d8dd; text-align:right;">Current Amount</th>
                        <th style="padding:7px; border:1px solid #d1d8dd; text-align:center;">Status</th>
                    </tr>
                </thead>
                <tbody>
                    ${rows.join('')}
                    ${extra_rows.join('')}
                </tbody>
            </table>
        </div>
    `;
}

function show_quotation_items_dialog(frm, cdt, cdn) {
    if (!frm.doc.custom_quotation) {
        frappe.msgprint(__('Please select a Quotation first.'));
        return;
    }

    frappe.call({
        method: 'frappe.client.get',
        args: {
            doctype: 'Quotation',
            name: frm.doc.custom_quotation
        },
        callback: function(r) {
            if (!r.message) return;
            let quotation_items = r.message.items;
            let quotation_item_codes = quotation_items.map(i => i.item_code);
            let contract_value = flt(frm.doc.custom_total_contract_value);

            let row = locals[cdt][cdn];
            if (row.milestone_items_json) {
                try {
                    window._quotation_items = JSON.parse(row.milestone_items_json);
                } catch(e) {
                    window._quotation_items = quotation_items.map(item => ({
                        item_code: item.item_code,
                        item_name: item.item_name,
                        qty: item.qty,
                        amount: item.amount,
                        original_amount: item.amount,
                        milestone_percentage: 0,
                        milestone_amount: 0
                    }));
                }
            } else {
                window._quotation_items = quotation_items.map(item => ({
                    item_code: item.item_code,
                    item_name: item.item_name,
                    qty: item.qty,
                    amount: item.amount,
                    original_amount: item.amount,
                    milestone_percentage: 0,
                    milestone_amount: 0
                }));
            }

            function update_comparison() {
                $('#comparison_table').html(
                    render_comparison_table(quotation_items, window._quotation_items)
                );
            }

            function recalculate_totals() {
                let total_pct = 0, total_amt = 0, total_amount = 0;
                window._quotation_items.forEach(item => {
                    total_pct += flt(item.milestone_percentage);
                    total_amt += flt(item.milestone_amount);
                    total_amount += flt(item.amount);
                });
                $('#total_milestone_pct').text(flt(total_pct, 2) + '%');
                $('#total_milestone_amt').text('INR ' + flt(total_amt, 2));
                $('#total_amount').text('INR ' + flt(total_amount, 2));

                let coverage = contract_value > 0 ? flt((total_amt / contract_value) * 100, 2) : 0;
                let remaining = flt(contract_value - total_amt, 2);
                let color = coverage >= 100 ? 'green' : 'orange';
                let msg = coverage >= 100
                    ? `✅ Covers ${coverage}% of Contract Value`
                    : `⚠️ Covers ${coverage}% of Contract Value. Remaining: INR ${remaining}`;
                $('#coverage_status').text(msg).css('color', color);

                update_comparison();
            }

            function check_warnings(idx) {
                let item = window._quotation_items[idx];
                if (!item.item_code) return;
                let original = quotation_items[idx] || quotation_items.find(q => q.item_code === item.item_code);
                let warning = '';
                if (!original) {
                    warning = '⚠️ Item not in Quotation';
                } else if (flt(item.amount) > flt(original.amount)) {
                    let diff = flt(item.amount) - flt(original.amount);
                    let times = flt(item.amount / original.amount, 2);
                    warning = `⚠️ Greater than Quotation by INR ${diff} (${times}x of Quotation amount)`;
                } else if (flt(item.amount) < flt(original.amount)) {
                    let diff = flt(original.amount) - flt(item.amount);
                    let pct = flt(((original.amount - item.amount) / original.amount) * 100, 2);
                    warning = `⚠️ Less than Quotation by INR ${diff} (${pct}% less than Quotation amount)`;
                }
                $(`#warn_${idx}`).text(warning).css('color', 'orange');
            }

            function check_all_warnings() {
                window._quotation_items.forEach((item, idx) => check_warnings(idx));
            }

            function render_table() {
                let rows = window._quotation_items.map((item, idx) => `
                    <tr>
                        <td style="padding:6px; border:1px solid #d1d8dd;">
                            <input type="text" value="${item.item_code}"
                                style="width:90px; border:none; outline:none;"
                                onchange="window._quotation_items[${idx}].item_code = this.value; window._check_warnings(${idx}); window._update_comparison();"/>
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd;">
                            <input type="text" value="${item.item_name}"
                                style="width:120px; border:none; outline:none;"
                                onchange="window._quotation_items[${idx}].item_name = this.value;"/>
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd;">
                            <input type="number" value="${item.qty}"
                                style="width:60px; border:none; outline:none; text-align:right;"
                                onchange="window._quotation_items[${idx}].qty = parseFloat(this.value)||0;"/>
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd;">
                            <input type="number" value="${item.amount}"
                                style="width:90px; border:none; outline:none; text-align:right;"
                                onchange="
                                    window._quotation_items[${idx}].amount = parseFloat(this.value)||0;
                                    window._check_warnings(${idx});
                                    window._quotation_items[${idx}].milestone_amount = flt((window._quotation_items[${idx}].amount * window._quotation_items[${idx}].milestone_percentage) / 100, 2);
                                    $('#ms_amt_${idx}').text(window._quotation_items[${idx}].milestone_amount);
                                    window._recalculate_totals();
                                "/>
                            <div id="warn_${idx}" style="font-size:11px; color:orange;"></div>
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd;">
                            <input type="number" value="${item.milestone_percentage}"
                                style="width:60px; border:none; outline:none; text-align:right;"
                                onchange="
                                    window._quotation_items[${idx}].milestone_percentage = parseFloat(this.value)||0;
                                    window._quotation_items[${idx}].milestone_amount = flt((window._quotation_items[${idx}].amount * window._quotation_items[${idx}].milestone_percentage) / 100, 2);
                                    $('#ms_amt_${idx}').text(window._quotation_items[${idx}].milestone_amount);
                                    window._recalculate_totals();
                                "/>
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd; text-align:right;" id="ms_amt_${idx}">
                            ${flt(item.milestone_amount, 2)}
                        </td>
                        <td style="padding:6px; border:1px solid #d1d8dd; text-align:center;">
                            <button class="btn btn-xs btn-danger"
                                onclick="window._delete_item(${idx})">✕</button>
                        </td>
                    </tr>
                `).join('');

                return `
                    <div style="overflow-x:auto;">
                    <table style="width:100%; border-collapse:collapse; font-size:12px;">
                        <thead>
                            <tr style="background:#f4f5f6; font-weight:bold;">
                                <th style="padding:8px; border:1px solid #d1d8dd;">Item Code</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Item Name</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Qty</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Amount</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Milestone %</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Milestone Amount</th>
                                <th style="padding:8px; border:1px solid #d1d8dd;">Delete</th>
                            </tr>
                        </thead>
                        <tbody>${rows}</tbody>
                        <tfoot>
                            <tr style="background:#f4f5f6; font-weight:bold;">
                                <td colspan="3" style="padding:8px; border:1px solid #d1d8dd; text-align:right;">Total:</td>
                                <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;" id="total_amount">INR 0</td>
                                <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;" id="total_milestone_pct">0%</td>
                                <td style="padding:8px; border:1px solid #d1d8dd; text-align:right;" id="total_milestone_amt">INR 0</td>
                                <td style="border:1px solid #d1d8dd;"></td>
                            </tr>
                            <tr>
                                <td colspan="7" style="padding:8px; border:1px solid #d1d8dd; text-align:center; font-size:12px;" id="coverage_status"></td>
                            </tr>
                            <tr style="background:#fff8e1;">
                                <td colspan="7" style="padding:8px; border:1px solid #d1d8dd; text-align:center; font-size:12px;">
                                    💡 Total Contract Value = <b>INR ${flt(contract_value, 2)}</b>
                                </td>
                            </tr>
                        </tfoot>
                    </table>
                    </div>
                    <button class="btn btn-xs btn-default" style="margin-top:8px;"
                        onclick="window._add_item()">+ Add Row</button>
                    <div id="comparison_table"></div>
                `;
            }

            let d = new frappe.ui.Dialog({
                title: __('Items - ' + frm.doc.custom_quotation),
                fields: [{
                    fieldtype: 'HTML',
                    fieldname: 'items_table',
                    options: render_table()
                }],
                primary_action_label: __('Save'),
                primary_action: function() {
                    let zero_pct = window._quotation_items.filter(item => item.item_code && flt(item.milestone_percentage) === 0);
                    if (zero_pct.length > 0) {
                        frappe.msgprint({
                            message: __('Please enter Milestone % for all items before saving.'),
                            indicator: 'red',
                            title: 'Validation Error'
                        });
                        return;
                    }
                    let total_amt = 0;
                    window._quotation_items.forEach(item => {
                        total_amt += flt(item.milestone_amount);
                    });

                    let milestone_pct = flt(window._quotation_items.reduce((sum, item) => {
                        return sum + flt(item.milestone_percentage);
                    }, 0), 2);

                    frappe.model.set_value(cdt, cdn, 'milestone_items_json',
                        JSON.stringify(window._quotation_items));
                    frappe.model.set_value(cdt, cdn, 'percentage', milestone_pct);
                    frappe.model.set_value(cdt, cdn, 'amount', flt(total_amt, 2));
                    frm.refresh_field('custom_project_milestones');
                    render_summary_table(frm);

                    d.hide();
                    frappe.msgprint({
                        message: __('Items saved! This milestone covers <b>' + milestone_pct + '%</b> of Total Contract Value.'),
                        indicator: milestone_pct >= 100 ? 'green' : 'orange',
                        alert: 1
                    });
                }
            });

            window._recalculate_totals = recalculate_totals;
            window._check_warnings = check_warnings;
            window._update_comparison = update_comparison;

            window._delete_item = function(idx) {
                let deleted = window._quotation_items[idx];
                if (quotation_item_codes.includes(deleted.item_code)) {
                    frappe.msgprint({
                        message: `⚠️ Item <b>${deleted.item_code}</b> exists in Quotation but is being deleted!`,
                        indicator: 'orange',
                        title: 'Warning'
                    });
                }
                window._quotation_items.splice(idx, 1);
                d.fields_dict.items_table.$wrapper.html(render_table());
                setTimeout(() => { recalculate_totals(); check_all_warnings(); }, 100);
            };

            window._add_item = function() {
                let item_dialog = new frappe.ui.Dialog({
                    title: __('Add Item'),
                    fields: [{
                        fieldtype: 'Link',
                        fieldname: 'item_code',
                        label: 'Item Code',
                        options: 'Item',
                        reqd: 1
                    }, {
                        fieldtype: 'Float',
                        fieldname: 'qty',
                        label: 'Qty',
                        default: 1
                    }, {
                        fieldtype: 'Currency',
                        fieldname: 'amount',
                        label: 'Amount',
                        default: 0
                    }],
                    primary_action_label: __('Add'),
                    primary_action: function(values) {
                        if (!values.item_code) return;
                        frappe.db.get_value('Item', values.item_code, 'item_name')
                            .then(r => {
                                window._quotation_items.push({
                                    item_code: values.item_code,
                                    item_name: r.message.item_name || values.item_code,
                                    qty: values.qty || 1,
                                    amount: values.amount || 0,
                                    original_amount: 0,
                                    milestone_percentage: 0,
                                    milestone_amount: 0
                                });
                                d.fields_dict.items_table.$wrapper.html(render_table());
                                setTimeout(() => {
                                    recalculate_totals();
                                    check_all_warnings();
                                }, 100);
                                item_dialog.hide();
                                frappe.msgprint({
                                    message: '⚠️ New item added. Make sure it is from the Quotation.',
                                    indicator: 'orange',
                                    title: 'Warning'
                                });
                            });
                    }
                });
                item_dialog.show();
            };

            d.show();

            setTimeout(function() {
                check_all_warnings();
                recalculate_totals();
                update_comparison();
            }, 300);
        }
    });
}

function calculate_totals(frm) {
    let total_milestone_amount = 0.0;
    $.each(frm.doc.custom_project_milestones || [], function(i, row) {
        total_milestone_amount += flt(row.amount);
    });
    let contract_value = flt(frm.doc.custom_total_contract_value);
    let coverage_pct = contract_value > 0 ? flt((total_milestone_amount / contract_value) * 100, 2) : 0.0;
    if (coverage_pct > 100.01) {
        frappe.msgprint({
            title: __('Validation Error'),
            indicator: 'red',
            message: __('Total Milestone Amount exceeds Total Contract Value. Coverage is <b>{0}%</b>', [coverage_pct])
        });
        frappe.validated = false;
    }
    frm.set_value('custom_total_completed__', coverage_pct);
}

