    const dialog = new frappe.ui.Dialog({
        title: __('Bulk Price Update'),
        size: 'extra-large',
        fields: [
            {
                fieldname: 'controls_html',
                fieldtype: 'HTML'
            },
            {
                fieldname: 'items_html',
                fieldtype: 'HTML'
            }
