function load_price_lists(dialog) {
    const $controls = dialog.fields_dict.controls_html.$wrapper;

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Price List',
            filters: { buying: 1, enabled: 1 },
            fields: ['name'],
            limit_page_length: 0
        },
        async: false,
        callback: function(r) {
            const $select = $controls.find('.buying-pl-select');
            $select.html('<option value="">Select...</option>');
            (r.message || []).forEach(pl => {
                $select.append(`<option value="${pl.name}">${pl.name}</option>`);
            });
        }
    });

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Price List',
            filters: { selling: 1, enabled: 1 },
            fields: ['name'],
            limit_page_length: 0
        },
        async: false,
        callback: function(r) {
            const $select = $controls.find('.selling-pl-select');
            $select.html('<option value="">Select...</option>');
            (r.message || []).forEach(pl => {
                $select.append(`<option value="${pl.name}">${pl.name}</option>`);
            });
        }
    });
}

function get_control_values(dialog) {
    const $controls = dialog.fields_dict.controls_html.$wrapper;
    return {
        buying_price_list: $controls.find('.buying-pl-select').val(),
        selling_price_list: $controls.find('.selling-pl-select').val(),
        calc_type: $controls.find('.calc-type-select').val(),
        calc_percent: parseFloat($controls.find('.calc-percent-input').val()) || 0,
        round_to: parseInt($controls.find('.round-select').val()) || 0
    };
}

function refresh_prices(dialog) {
    const values = get_control_values(dialog);

    if (!values.buying_price_list || !values.selling_price_list) return;

    dialog.fields_dict.items_html.$wrapper.html(`
        <div class="text-center text-muted py-5">
            <i class="fa fa-spinner fa-spin fa-2x"></i>
            <p class="mt-2">${__('Loading prices...')}</p>
        </div>
    `);

    frappe.call({
        method: 'cecypo_powerpack.api.fetch_item_prices',
        args: {
            item_codes_str: dialog.item_codes.join('|||'),
            buying_price_list: values.buying_price_list,
            selling_price_list: values.selling_price_list
        },
        callback: function(r) {
            dialog.items_data = r.message || [];
            render_items_table(dialog, dialog.items_data);
        },
        error: function(err) {
            frappe.msgprint(__('Error fetching prices'));
            render_items_table(dialog, []);
        }
    });
}

function update_table_header(dialog) {
    const values = get_control_values(dialog);
    const label = values.calc_type === 'markup' ? __('Markup') : __('Margin');
    dialog.fields_dict.items_html.$wrapper.find('.percent-header').text(label);
}

function recalculate_percentages(dialog) {
    const values = get_control_values(dialog);
    const $wrapper = dialog.fields_dict.items_html.$wrapper;

    dialog.items_data.forEach((item, idx) => {
        const cost = item.cost_price || 0;
        const sell = item.sell_price || 0;
        const pct = calculate_percentage(cost, sell, values.calc_type);

        $wrapper.find(`.percent-display[data-idx="${idx}"]`).html(
            `<span class="${get_percent_class(pct)}">${pct}%</span>`
        );
    });
}

function calculate_percentage(cost, sell, calc_type) {
    if (calc_type === 'markup') {
        return cost > 0 ? (((sell - cost) / cost) * 100).toFixed(1) : '—';
    } else {
        return sell > 0 ? (((sell - cost) / sell) * 100).toFixed(1) : '—';
    }
}

function calculate_sell_price(cost, percent, calc_type) {
    if (calc_type === 'markup') {
        return cost * (1 + percent / 100);
    } else {
        if (percent >= 100) return cost * 10;
        return cost / (1 - percent / 100);
    }
}

