            <table class="table table-sm" style="margin-bottom: 0; font-size: 12px;">
                <thead style="position: sticky; top: 0; background: var(--subtle-fg); z-index: 1;">
                    <tr>
                        <th style="width: 35px; text-align: center; padding: 8px 4px;">
