function bind_table_events(dialog) {
    const $wrapper = dialog.fields_dict.items_html.$wrapper;

    $wrapper.find('.select-all-items').off('change').on('change', function() {
        const checked = $(this).is(':checked');
        $wrapper.find('.item-checkbox').prop('checked', checked);
        update_selected_count(dialog);
    });

    $wrapper.find('.item-checkbox').off('change').on('change', function() {
        update_selected_count(dialog);
        const total = $wrapper.find('.item-checkbox').length;
        const checked = $wrapper.find('.item-checkbox:checked').length;
        $wrapper.find('.select-all-items').prop('checked', total === checked);
    });

    $wrapper.find('.sell-price-input').off('input').on('input', function() {
        const idx = $(this).data('idx');
        const new_price = parseFloat($(this).val()) || 0;
        const values = get_control_values(dialog);

        dialog.items_data[idx].sell_price = new_price;

        const cost = dialog.items_data[idx].cost_price || 0;
        const pct = calculate_percentage(cost, new_price, values.calc_type);

        $wrapper.find(`.percent-display[data-idx="${idx}"]`).html(
            `<span class="${get_percent_class(pct)}">${pct}%</span>`
        );
    });
}

function update_selected_count(dialog) {
    const $wrapper = dialog.fields_dict.items_html.$wrapper;
    const checked = $wrapper.find('.item-checkbox:checked').length;
    $wrapper.find('.selected-count').text(checked);
}

function apply_calculation_to_all(dialog) {
    const values = get_control_values(dialog);

    if (!dialog.items_data.length) {
        frappe.msgprint(__('No items loaded. Please select both price lists first.'));
        return;
    }

    const $wrapper = dialog.fields_dict.items_html.$wrapper;
    let updated = 0;

    dialog.items_data.forEach((item, idx) => {
        if (!$wrapper.find(`.item-checkbox[data-idx="${idx}"]`).is(':checked')) return;

        const cost = item.cost_price || 0;
        let new_price = calculate_sell_price(cost, values.calc_percent, values.calc_type);

        if (values.round_to > 0) {
            new_price = Math.ceil(new_price / values.round_to) * values.round_to;
        }

        item.sell_price = new_price;
        $wrapper.find(`.sell-price-input[data-idx="${idx}"]`).val(new_price.toFixed(2));

        const actual_pct = calculate_percentage(cost, new_price, values.calc_type);

        $wrapper.find(`.percent-display[data-idx="${idx}"]`).html(
            `<span class="${get_percent_class(actual_pct)}">${actual_pct}%</span>`
        );
        updated++;
    });

    const typeLabel = values.calc_type === 'markup' ? __('Markup') : __('Margin');
    frappe.show_alert({ message: __('{0} applied to {1} items', [typeLabel, updated]), indicator: 'green' }, 3);
}

function save_prices(dialog) {
    const values = get_control_values(dialog);

    if (!values.selling_price_list) {
        frappe.msgprint(__('Please select a Selling Price List'));
        return;
    }

    const $wrapper = dialog.fields_dict.items_html.$wrapper;
    const items_to_update = [];

    dialog.items_data.forEach((item, idx) => {
        if ($wrapper.find(`.item-checkbox[data-idx="${idx}"]`).is(':checked')) {
            items_to_update.push(
                item.item_code + '::' + (parseFloat($wrapper.find(`.sell-price-input[data-idx="${idx}"]`).val()) || 0)
            );
        }
    });

    if (!items_to_update.length) {
        frappe.msgprint(__('No items selected for update'));
        return;
    }

    dialog.disable_primary_action();

    frappe.call({
        method: 'cecypo_powerpack.api.save_item_prices',
        args: {
            items_str: items_to_update.join('|||'),
            selling_price_list: values.selling_price_list
        },
        callback: function(r) {
            if (r.message) {
                frappe.show_alert({
                    message: __('Updated {0} prices', [r.message.updated_count]),
                    indicator: 'green'
                }, 5);
                dialog.hide();
            }
        },
        error: function() {
            frappe.msgprint(__('Error saving prices'));
        },
        always: function() {
            dialog.enable_primary_action();
        }
    });
}

function format_currency(value, currency) {
    if (value === null || value === undefined || value === 0) return '—';
    return frappe.format(value, { fieldtype: 'Currency', currency: currency });
}

function get_percent_class(pct) {
    if (pct === '—') return 'text-muted';
    const p = parseFloat(pct);
    if (p < 0) return 'text-danger';
    if (p < 10) return 'text-warning';
    if (p < 20) return 'text-info';
    return 'text-success';
}

